using System;
using System.Drawing;
using System.IO;

namespace CastleGuardGame
{
    internal static class ResourceLoader
    {
        private static Image Load(string b64)
        {
            byte[] data = Convert.FromBase64String(b64);
            return Image.FromStream(new MemoryStream(data));
        }

        private static readonly string _archer     = "";
        private static readonly string _arrow      = "";
        private static readonly string _gargoyle   = "";
        private static readonly string _fireball   = "";
        private static readonly string _boulder    = "";
        private static readonly string _background = "";

        public static Image Archer     => Load(_archer);
        public static Image Arrow      => Load(_arrow);
        public static Image Gargoyle   => Load(_gargoyle);
        public static Image Fireball   => Load(_fireball);
        public static Image Boulder    => Load(_boulder);
        public static Image Background => Load(_background);
    }
}
